trigger.body:
    vSymbol NUMBER;
    cRow RECORD;
    vNewQty NUMBER;
BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

    IF UPDATING THEN
        IF :OLD.processed = :NEW.processed THEN
            RETURN NEW;
        END IF;

        vSymbol := 1;
        IF :OLD.processed = 'Y' AND :NEW.processed = 'N' THEN
            vSymbol := -1;
        END IF;

        FOR cRow IN (
            SELECT ml.line, ml.movementqty, tp.sproctm_task_prod_id, tp.qty, tp.em_ssprj_qty_transferred
            FROM m_movementline ml
                JOIN sproctm_task_prod tp ON tp.sproctm_task_prod_id = ml.em_ssprj_task_prod_id
            WHERE ml.m_movement_id = :NEW.m_movement_id
        ) LOOP
            vNewQty := cRow.em_ssprj_qty_transferred + (cRow.movementqty * vSymbol);
            IF vNewQty > cRow.qty THEN
                RAISE_APPLICATION_ERROR(-20000, 'La línea '||cRow.line||' excede la cantidad requerida por la línea de producto en el proyecto');
            END IF;

            UPDATE sproctm_task_prod SET em_ssprj_qty_transferred = vNewQty WHERE sproctm_task_prod_id = cRow.sproctm_task_prod_id;
        END LOOP;
    END IF;

    END SSPRJ_MOVEMENT_PROJ_PROD_TRG
